import { LeaveStatus, LeaveSize, LeaveType, type Guid } from '@/api/leaveService';

export type LeaveActionType =
    | 'approve'
    | 'reject'
    | 'restore'
    | 'delete'
    | 'consumed'
    | 'not-consumed'
    | 'finalize';

export interface PendingAction {
    id: Guid;
    type: LeaveActionType;
    title: string;
    message: string;
    confirmLabel: string;
    confirmVariant: 'primary' | 'danger' | 'warning';
    payload?: {
        rejectionNotes?: string;
    };
}

export interface LeaveCreateForm {
    userProfileId: string;
    leaveDate: string;
    leaveSize: LeaveSize;
    leaveType: LeaveType;
    reason: string;
    notes: string;
}

export interface LeaveEditForm {
    id: string;
    leaveSize: LeaveSize;
    leaveType: LeaveType;
    reason: string;
    notes: string;
}

export interface EmployeeOption {
    id: string;
    name: string;
}

export const statusOptions = [
    { label: 'All', value: '' },
    { label: 'Submitted', value: String(LeaveStatus.Submitted) },
    { label: 'Approved', value: String(LeaveStatus.Approved) },
    { label: 'Rejected', value: String(LeaveStatus.Rejected) },
    { label: 'Consumed', value: String(LeaveStatus.Consumed) },
    { label: 'Not Consumed', value: String(LeaveStatus.NotConsumed) },
    { label: 'Finalized', value: String(LeaveStatus.Finalized) },
] as const;

export const leaveTypeOptions = [
    { label: 'Planned', value: String(LeaveType.Planned) },
    { label: 'Unplanned', value: String(LeaveType.Unplanned) },
] as const;

export function getActionText(type: LeaveActionType): string {
    switch (type) {
        case 'approve':
            return 'Approve';
        case 'reject':
            return 'Reject';
        case 'delete':
            return 'Delete';
        case 'consumed':
            return 'Mark Consumed';
        case 'not-consumed':
            return 'Mark Not Consumed';
        case 'finalize':
            return 'Finalize';
        case 'restore':
            return 'Restore';
        default:
            return 'Confirm';
    }
}