import { useMemo, useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { Alert, AlertDescription } from '@/shadcn/components/ui/alert';
import { Button } from '@/shadcn/components/ui/button';
import { HarmonyAlertDialog } from "@/components/ui/harmony-alert-dialog";
import { ServerPaginationTable, type ServerTableColumn } from '@/components/ui/grid/ServerPaginationTable';
import { userService as accountService } from '@/api/auth/userService';
import { getLeaveErrorMessage, type LeaveStructureInputDTO } from '@/api/leaveService';
import { useMonthlyLeaveQuery, useStructureByUserQuery, useStructureListQuery } from '@/features/leave-management/hooks/leaveHooks';
import { queryKeys } from '@/lib/queryKeys';
import { PermissionGate } from '@/components/shared/PermissionGate';
import { PERMISSIONS } from '@/constants/permissions';
import { useLeaveStructureActions } from '../hooks/useLeaveStructureActions';

interface DraftStructureRow {
    _tempId?: string;
    effectiveFrom: string;
    effectiveTill: string;
    paidLeaves: number;
    notes: string;
}

interface LeaveStructureGroupRow {
    userProfileId: string;
    leaveStructures: unknown[];
}

const emptyDraftRow = (): DraftStructureRow => ({
    _tempId: Date.now().toString() + Math.random().toString(36).slice(2),
    effectiveFrom: '',
    effectiveTill: '',
    paidLeaves: 1,
    notes: '',
});

export default function LeaveStructure() {
    const [pageIndex, setPageIndex] = useState(1);
    const [pageSize, setPageSize] = useState(10);
    const [selectedUserId, setSelectedUserId] = useState('');
    const [previewMonth, setPreviewMonth] = useState(new Date().getMonth() + 1);
    const [previewYear, setPreviewYear] = useState(new Date().getFullYear());
    const [errorMessage] = useState('');
    const [successMessage, setSuccessMessage] = useState('');
    const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
    const [draftRows, setDraftRows] = useState<DraftStructureRow[]>([emptyDraftRow()]);

    // ── Queries & Hooks ──────────────────────────────────────────────────────
    const employeesQuery = useQuery({
        queryKey: queryKeys.leaveManagement.employees(),
        queryFn: () => accountService.getEmployees(),
        staleTime: 5 * 60 * 1000,
    });

    const listQuery = useStructureListQuery({
        pageIndex,
        pageSize,
        userProfileId: selectedUserId || undefined,
    });

    const userRowsQuery = useStructureByUserQuery(selectedUserId, {
        enabled: Boolean(selectedUserId),
    });

    const monthlyPreviewQuery = useMonthlyLeaveQuery(selectedUserId, previewMonth, previewYear, {
        enabled: Boolean(selectedUserId),
    });

    const { generateMutation, updateMutation, deleteMutation, errorMessage: actionError } = useLeaveStructureActions();

    // ── Logic ────────────────────────────────────────────────────────────────
    const employeeOptions = useMemo(() => {
        const employees = Array.isArray(employeesQuery.data) ? employeesQuery.data : [];
        return employees.map((employee) => {
            const id = employee.userProfileId || employee.id || '';
            const name = employee.fullName || employee.name || id;
            return { id, name };
        }).filter(e => e.id);
    }, [employeesQuery.data]);

    const groupedColumns: Array<ServerTableColumn<LeaveStructureGroupRow>> = [
        {
            key: 'userProfileId',
            header: 'User Profile',
            render: (row) => <span className="font-semibold text-foreground">{row.userProfileId.slice(0, 8)}</span>,
        },
        {
            key: 'rows',
            header: 'Entitlements',
            render: (row) => <span className="badge badge-gray">{row.leaveStructures.length} Rows</span>,
        },
        {
            key: 'actions',
            header: 'Actions',
            className: 'text-right',
            render: (row) => (
                <Button variant="link" className="h-auto p-0" type="button" onClick={() => setSelectedUserId(row.userProfileId)}>
                    Manage User
                </Button>
            ),
        },
    ];

    const monthOptions = Array.from({ length: 12 }, (_, i) => ({ value: i + 1, label: String(i + 1).padStart(2, '0') }));

    return (
        <div className="space-y-6">

            {(errorMessage || actionError) && (
                <Alert variant="destructive"><AlertDescription>{errorMessage || actionError}</AlertDescription></Alert>
            )}
            {successMessage && (
                <div className="flex items-center gap-2 rounded-lg border border-primary/20 bg-primary/10 px-4 py-3 text-sm text-primary">{successMessage}</div>
            )}

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
                <div className="lg:col-span-4 space-y-6">
                    <section className="section-card">
                        <div className="section-card-header">
                            <h3 className="section-card-title">User Selection</h3>
                        </div>
                        <div className="p-5 space-y-4">
                            <div>
                                <label className="form-label">Employee</label>
                                <select value={selectedUserId} onChange={(e) => setSelectedUserId(e.target.value)} className="form-input">
                                    <option value="">Select user</option>
                                    {employeeOptions.map(opt => <option key={opt.id} value={opt.id}>{opt.name}</option>)}
                                </select>
                            </div>
                            <div className="grid grid-cols-2 gap-3">
                                <div>
                                    <label className="form-label">Month</label>
                                    <select value={previewMonth} onChange={(e) => setPreviewMonth(Number(e.target.value))} className="form-input">
                                        {monthOptions.map(m => <option key={m.value} value={m.value}>{m.label}</option>)}
                                    </select>
                                </div>
                                <div>
                                    <label className="form-label">Year</label>
                                    <input type="number" value={previewYear} onChange={(e) => setPreviewYear(Number(e.target.value))} className="form-input" />
                                </div>
                            </div>
                        </div>
                    </section>

                    <div className="stat-card bg-primary text-primary-foreground">
                        <p className="stat-card-label text-primary-foreground/70">Monthly Entitlement</p>
                        <p className="stat-card-value">
                            {selectedUserId ? (monthlyPreviewQuery.isLoading ? '...' : (Number(monthlyPreviewQuery.data ?? 0)).toFixed(2)) : '0.00'}
                        </p>
                    </div>
                </div>

                <div className="lg:col-span-8 space-y-6">
                    <section className="section-card no-gap">
                        <ServerPaginationTable
                            columns={groupedColumns}
                            rows={listQuery.data?.data ?? []}
                            rowKey={(row) => row.userProfileId}
                            isLoading={listQuery.isLoading}
                            errorMessage={listQuery.error ? getLeaveErrorMessage(listQuery.error) : null}
                            pagination={{
                                pageIndex: listQuery.data?.pageIndex ?? pageIndex,
                                pageSize: listQuery.data?.pageSize ?? pageSize,
                                totalCount: listQuery.data?.totalCount ?? 0,
                                totalPages: listQuery.data?.totalPages ?? 1,
                                hasNextPage: listQuery.data?.hasNextPage ?? false,
                                hasPreviousPage: listQuery.data?.hasPreviousPage ?? false,
                            }}
                            onPageChange={setPageIndex}
                            onPageSizeChange={setPageSize}
                        />
                    </section>
                </div>
            </div>

            {selectedUserId && (
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                    <section className="section-card">
                        <div className="section-card-header">
                            <h3 className="section-card-title">Existing Entitlements</h3>
                            <PermissionGate permission={PERMISSIONS.LeaveStructure.Delete}>
                                <Button variant="destructive" size="xs" onClick={() => setDeleteConfirmOpen(true)}>Delete All</Button>
                            </PermissionGate>
                        </div>
                        <div className="overflow-x-auto">
                            <table className="data-table">
                                <thead>
                                    <tr>
                                        <th>From</th>
                                        <th>Till</th>
                                        <th>Paid</th>
                                        <th className="text-right">Actions</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {userRowsQuery.data?.map(row => (
                                        <EditableStructureRow
                                            key={row.id}
                                            row={row as unknown as DraftStructureRow}
                                            onSave={(payload) => {
                                                if (!row.id) return;
                                                setSuccessMessage('');
                                                updateMutation.mutate({ id: row.id, data: payload as unknown as LeaveStructureInputDTO }, {
                                                    onSuccess: () => setSuccessMessage('Entitlement row updated.')
                                                });
                                            }}
                                            isLoading={updateMutation.isPending}
                                        />
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </section>

                    <section className="section-card">
                        <div className="section-card-header">
                            <h3 className="section-card-title">Generate New Structure</h3>
                            <Button variant="outline" size="xs" onClick={() => setDraftRows(p => [...p, emptyDraftRow()])}>Add Row</Button>
                        </div>
                        <div className="p-5 space-y-4">
                            {draftRows.map((row, idx) => (
                                <div key={row._tempId ?? idx} className="p-4 bg-muted/50 rounded-xl border border-border space-y-3">
                                    <div className="grid grid-cols-2 gap-3">
                                        <div>
                                            <label className="form-label">Effective From</label>
                                            <input type="date" value={row.effectiveFrom} onChange={e => setDraftRows(p => p.map((r, i) => i === idx ? { ...r, effectiveFrom: e.target.value } : r))} className="form-input" />
                                        </div>
                                        <div>
                                            <label className="form-label">Effective Till</label>
                                            <input type="date" value={row.effectiveTill} onChange={e => setDraftRows(p => p.map((r, i) => i === idx ? { ...r, effectiveTill: e.target.value } : r))} className="form-input" />
                                        </div>
                                    </div>
                                    <div className="grid grid-cols-2 gap-3">
                                        <div>
                                            <label className="form-label">Paid Leaves / Year</label>
                                            <input type="number" step={0.5} value={row.paidLeaves} onChange={e => setDraftRows(p => p.map((r, i) => i === idx ? { ...r, paidLeaves: Number(e.target.value) } : r))} className="form-input" />
                                        </div>
                                        <div className="flex items-end">
                                            <Button variant="destructive" className="w-full" onClick={() => setDraftRows(p => p.filter((_, i) => i !== idx))} disabled={draftRows.length === 1}>Remove Row</Button>
                                        </div>
                                    </div>
                                </div>
                            ))}
                            <PermissionGate permission={PERMISSIONS.LeaveStructure.Create}>
                                <Button
                                    className="w-full"
                                    onClick={() => generateMutation.mutate({ userId: selectedUserId, rows: draftRows }, {
                                        onSuccess: () => { setSuccessMessage('Structure generated.'); setDraftRows([emptyDraftRow()]); }
                                    })}
                                    disabled={generateMutation.isPending}
                                >
                                    Generate Final Structure
                                </Button>
                            </PermissionGate>
                        </div>
                    </section>
                </div>
            )}

            <HarmonyAlertDialog
                open={deleteConfirmOpen}
                onOpenChange={(open) => { if (!open) setDeleteConfirmOpen(false); }}
                title="Wipe User Entitlements"
                description="This will delete all leave structure rows for this user. This cannot be undone."
                variant="danger"
                actionLabel="Wipe All"
                onAction={() => {
                    if (selectedUserId) {
                        deleteMutation.mutate(selectedUserId, { onSuccess: () => setDeleteConfirmOpen(false) });
                    }
                }}
                isActioning={deleteMutation.isPending}
            />
        </div>
    );
}

function EditableStructureRow({ row, onSave, isLoading }: { row: DraftStructureRow; onSave: (p: Partial<DraftStructureRow>) => void; isLoading: boolean }) {
    const [effFrom, setEffFrom] = useState(row.effectiveFrom || '');
    const [effTill, setEffTill] = useState(row.effectiveTill || '');
    const [paid, setPaid] = useState(row.paidLeaves || 0);

    return (
        <tr>
            <td className="p-2"><input type="date" value={effFrom} onChange={e => setEffFrom(e.target.value)} className="form-input !py-1 text-xs" /></td>
            <td className="p-2"><input type="date" value={effTill} onChange={e => setEffTill(e.target.value)} className="form-input !py-1 text-xs" /></td>
            <td className="p-2"><input type="number" step={0.5} value={paid} onChange={e => setPaid(Number(e.target.value))} className="form-input !py-1 text-xs w-20" /></td>
            <td className="p-2 text-right">
                <PermissionGate permission={PERMISSIONS.LeaveStructure.Update}>
                    <Button
                        variant="link"
                        className="h-auto p-0 font-bold disabled:opacity-30"
                        disabled={isLoading}
                        onClick={() => onSave({ ...row, effectiveFrom: effFrom, effectiveTill: effTill, paidLeaves: paid })}
                    >
                        Save
                    </Button>
                </PermissionGate>
            </td>
        </tr>
    );
}