import { useMemo } from 'react';
import type { ServerTableColumn } from '@/components/ui/grid/ServerPaginationTable';
import { LeaveStatusChip } from '@/components/shared/WorkflowStatusChip';
import { leaveEnumLabels, LeaveStatus, type LeaveDTO } from '@/api/leaveService';
import { formatDate } from '@/utils/dateUtils';
import { PermissionGate } from '@/components/shared/PermissionGate';
import { PERMISSIONS } from '@/constants/permissions';

interface UseLeaveColumnsProps {
    onView: (id: string) => void;
    onEdit: (row: LeaveDTO) => void;
    onApprove: (id: string) => void;
    onReject: (id: string) => void;
    onDelete: (id: string) => void;
    onConsume: (id: string) => void;
    onNotConsume: (id: string) => void;
    onFinalize: (id: string) => void;
}

export function useLeaveColumns({
    onView,
    onEdit,
    onApprove,
    onReject,
    onDelete,
    onConsume,
    onNotConsume,
    onFinalize
}: UseLeaveColumnsProps) {
    return useMemo<Array<ServerTableColumn<LeaveDTO>>>(() => [
        {
            key: 'leaveDate',
            header: 'Date',
            render: (row) => <span className="font-semibold text-foreground">{formatDate(row.leaveDate)}</span>,
        },
        {
            key: 'leaveSize',
            header: 'Size',
            render: (row) => <span className="text-foreground font-medium">{leaveEnumLabels.leaveSize[row.leaveSize]}</span>,
        },
        {
            key: 'leaveType',
            header: 'Type',
            render: (row) => <span className="text-foreground">{leaveEnumLabels.leaveType[row.leaveType]}</span>,
        },
        {
            key: 'status',
            header: 'Status',
            render: (row) => <LeaveStatusChip value={row.status} size="sm" />,
        },
        {
            key: 'reason',
            header: 'Reason',
            className: 'max-w-[260px]',
            render: (row) => <span className="line-clamp-2 text-muted-foreground text-xs leading-relaxed">{row.reason}</span>,
        },
        {
            key: 'actions',
            header: 'Actions',
            className: 'min-w-[340px] text-right',
            render: (row) => (
                <div className="flex flex-wrap items-center justify-end gap-1.5">
                    <button 
                        type="button" 
                        className="px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest text-muted-foreground hover:bg-muted transition-all"
                        onClick={() => onView(row.id)}
                    >
                        View
                    </button>

                    {row.status === LeaveStatus.Submitted && (
                        <>
                            <PermissionGate permission={PERMISSIONS.Leave.Update}>
                                <button 
                                    type="button" 
                                    className="px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest text-primary hover:bg-primary/10 transition-all"
                                    onClick={() => onEdit(row)}
                                >
                                    Edit
                                </button>
                            </PermissionGate>

                            <PermissionGate permission={PERMISSIONS.Leave.Approve}>
                                <button 
                                    type="button" 
                                    className="px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest bg-emerald-50 text-emerald-700 hover:bg-emerald-600 hover:text-white shadow-sm transition-all" 
                                    onClick={() => onApprove(row.id)}
                                >
                                    Approve
                                </button>
                            </PermissionGate>

                            <PermissionGate permission={PERMISSIONS.Leave.Reject}>
                                <button 
                                    type="button" 
                                    className="px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest text-rose-600 hover:bg-rose-50 transition-all" 
                                    onClick={() => onReject(row.id)}
                                >
                                    Reject
                                </button>
                            </PermissionGate>

                            <PermissionGate permission={PERMISSIONS.Leave.Delete}>
                                <button 
                                    type="button" 
                                    className="px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest text-muted-foreground hover:text-destructive transition-all"
                                    onClick={() => onDelete(row.id)}
                                >
                                    Delete
                                </button>
                            </PermissionGate>
                        </>
                    )}

                    {row.status === LeaveStatus.Approved && (
                        <>
                            <PermissionGate permission={PERMISSIONS.Leave.Consume}>
                                <button 
                                    type="button" 
                                    className="px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest bg-primary/10 text-primary hover:bg-primary hover:text-primary-foreground shadow-sm transition-all"
                                    onClick={() => onConsume(row.id)}
                                >
                                    Consumed
                                </button>
                            </PermissionGate>

                            <PermissionGate permission={PERMISSIONS.Leave.Consume}>
                                <button 
                                    type="button" 
                                    className="px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest text-rose-600 hover:bg-rose-50 transition-all" 
                                    onClick={() => onNotConsume(row.id)}
                                >
                                    Not Consumed
                                </button>
                            </PermissionGate>
                        </>
                    )}

                    {row.status === LeaveStatus.NotConsumed && (
                        <PermissionGate permission={PERMISSIONS.Leave.Finalize}>
                            <button 
                                type="button" 
                                className="px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest bg-foreground text-background hover:bg-foreground/90 shadow-lg transition-all"
                                onClick={() => onFinalize(row.id)}
                            >
                                Finalize
                            </button>
                        </PermissionGate>
                    )}

                    {(row.status === LeaveStatus.Consumed || row.status === LeaveStatus.Finalized || row.status === LeaveStatus.Rejected) && (
                        <span className="px-3 py-1.5 text-[9px] font-black uppercase tracking-[0.15em] text-border">
                            Closed
                        </span>
                    )}
                </div>
            ),
        },
    ], [onView, onEdit, onApprove, onReject, onDelete, onConsume, onNotConsume, onFinalize]);
}
