import { useMutation, useQueryClient } from '@tanstack/react-query';
import { toast } from 'sonner';
import { leaveService } from '@/api/leaveService';
import { leaveQueryKeys } from '@/features/leave-management/hooks/leaveHooks';
import { getApiErrorMessage } from '@/api/app/apiError';
import { getLeaveErrorMessage } from '@/api/leaveService';

export function useLeaveCoverageActions() {
    const queryClient = useQueryClient();

    const selfAssignMutation = useMutation({
        mutationFn: (id: string) => leaveService.covered.selfAssign(id),
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: leaveQueryKeys.all });
        },
        onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to self-assign coverage')),
    });

    const assignMutation = useMutation({
        mutationFn: ({ id, assignedToUserId }: { id: string, assignedToUserId: string }) =>
            leaveService.covered.assign(id, { assignedToUserId }),
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: leaveQueryKeys.all });
        },
        onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to assign coverage')),
    });

    const acceptMutation = useMutation({
        mutationFn: (id: string) => leaveService.covered.accept(id),
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: leaveQueryKeys.all });
        },
        onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to accept coverage')),
    });

    const verifyMutation = useMutation({
        mutationFn: ({ id, notes }: { id: string, notes?: string }) =>
            leaveService.covered.verify(id, { notes }),
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: leaveQueryKeys.all });
        },
        onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to verify coverage')),
    });

    const cancelMutation = useMutation({
        mutationFn: (id: string) => leaveService.covered.cancel(id),
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: leaveQueryKeys.all });
        },
        onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to cancel coverage')),
    });

    return {
        selfAssignMutation,
        assignMutation,
        acceptMutation,
        verifyMutation,
        cancelMutation,
        errorMessage: selfAssignMutation.error || assignMutation.error || acceptMutation.error || verifyMutation.error || cancelMutation.error
            ? getLeaveErrorMessage(selfAssignMutation.error || assignMutation.error || acceptMutation.error || verifyMutation.error || cancelMutation.error)
            : null
    };
}
