import { useMutation, useQueryClient } from '@tanstack/react-query';
import { leaveService, getLeaveErrorMessage } from '@/api/leaveService';
import { leaveQueryKeys } from '@/features/leave-management/hooks/leaveHooks';
import { type LeaveActionType } from '../types/leave-types';

export function useLeaveMutations() {
    const queryClient = useQueryClient();

    const actionMutation = useMutation({
        mutationFn: ({ id, type, notes }: { id: string, type: LeaveActionType, notes?: string }) => {
            switch (type) {
                case 'approve': return leaveService.leaves.approve(id);
                case 'reject': return leaveService.leaves.reject(id, { rejectionNotes: notes || '' });
                case 'delete': return leaveService.leaves.remove(id);
                case 'consumed': return leaveService.leaves.markConsumed(id);
                case 'not-consumed': return leaveService.leaves.markNotConsumed(id);
                case 'finalize': return leaveService.leaves.finalize(id);
                case 'restore': return leaveService.leaves.restore(id);
                default: throw new Error(`Unsupported action type: ${type}`);
            }
        },
        onMutate: async () => {
            await queryClient.cancelQueries({ queryKey: leaveQueryKeys.all });
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: leaveQueryKeys.all });
        },
        onError: () => {
            // Error handled via return state
        }
    });

    return {
        actionMutation,
        errorMessage: actionMutation.error ? getLeaveErrorMessage(actionMutation.error) : null
    };
}
