import { useMutation, useQueryClient } from '@tanstack/react-query';
import { leaveService, getLeaveErrorMessage, type LeaveStructureInputDTO } from '@/api/leaveService';
import { leaveQueryKeys } from '@/features/leave-management/hooks/leaveHooks';
import { useState } from 'react';

export function useLeaveStructureActions() {
    const queryClient = useQueryClient();
    const [errorMessage, setErrorMessage] = useState('');

    const generateMutation = useMutation({
        mutationFn: (payload: { userId: string; rows: LeaveStructureInputDTO[] }) =>
            leaveService.structure.generate(payload.userId, payload.rows),
        onSuccess: async () => {
            setErrorMessage('');
            await queryClient.invalidateQueries({ queryKey: leaveQueryKeys.all });
        },
        onError: (err) => setErrorMessage(getLeaveErrorMessage(err)),
    });

    const updateMutation = useMutation({
        mutationFn: (payload: { id: string; data: LeaveStructureInputDTO }) =>
            leaveService.structure.update(payload.id, payload.data),
        onSuccess: async () => {
            setErrorMessage('');
            await queryClient.invalidateQueries({ queryKey: leaveQueryKeys.all });
        },
        onError: (err) => setErrorMessage(getLeaveErrorMessage(err)),
    });

    const deleteMutation = useMutation({
        mutationFn: (userId: string) => leaveService.structure.removeByUser(userId),
        onSuccess: async () => {
            setErrorMessage('');
            await queryClient.invalidateQueries({ queryKey: leaveQueryKeys.all });
        },
        onError: (err) => setErrorMessage(getLeaveErrorMessage(err)),
    });

    return {
        generateMutation,
        updateMutation,
        deleteMutation,
        errorMessage,
    };
}
